select
o.id, o.order_no, o.user_id, o.duration_id, o.duration_value, o.tier_id, o.tier_value, o.total_amount, o.odic_amount,
o.group_id_no, o.live_status, o.begin_time, o.end_time, o.channel_name, o.channel_id, o.remark,
o.create_time, o.update_time, o.create_by, o.update_by, o.is_deleted,
IFNULL(m.idno, '') AS user_idno,
IFNULL(
    (select gx.idno from t_group gx
     where o.group_id_no is not null and trim(o.group_id_no) != ''
       and (gx.id = trim(o.group_id_no) or gx.idno = trim(o.group_id_no))
     limit 1),
    ''
) AS tidno_group
from t_live_order_record o
left join t_member m on m.id = o.user_id
left join t_group g on g.id = o.group_id_no

    o.is_deleted = 0

        and o.id = #{id}


        and o.order_no = #{orderNo}


        and o.user_id = #{userId}


        and m.idno like concat('%', #{userIdno}, '%')


        and o.duration_id = #{durationId}


        and o.tier_id = #{tierId}


        and o.group_id_no = #{groupIdNo}


        and exists (select 1 from t_group gx where gx.idno like concat('%', #{groupIdno}, '%')
            and o.group_id_no is not null and trim(o.group_id_no) != ''
            and (gx.id = trim(o.group_id_no) or gx.idno = trim(o.group_id_no)))


        and g.idno like concat('%', #{tidnoGroup}, '%')


        and o.live_status = #{liveStatus}


        and o.begin_time >= #{beginTimeStart}


        and o.begin_time <= #{beginTimeEnd}



    order by ${orderBy}


    order by o.create_time desc


    limit #{pageNo}, #{pageSize}

select count(1)
from t_live_order_record o
left join t_member m on m.id = o.user_id

    o.is_deleted = 0

        and o.id = #{id}


        and o.order_no = #{orderNo}


        and o.user_id = #{userId}


        and m.idno like concat('%', #{userIdno}, '%')


        and o.duration_id = #{durationId}


        and o.tier_id = #{tierId}


        and o.group_id_no = #{groupIdNo}


        and exists (select 1 from t_group gx where gx.idno like concat('%', #{groupIdno}, '%')
            and o.group_id_no is not null and trim(o.group_id_no) != ''
            and (gx.id = trim(o.group_id_no) or gx.idno = trim(o.group_id_no)))


        and o.live_status = #{liveStatus}


        and o.begin_time >= #{beginTimeStart}


        and o.begin_time <= #{beginTimeEnd}

