insert into t_live_order_record (
    order_no, user_id, duration_id, duration_value, tier_id, tier_value, total_amount, group_id_no, live_status,
    begin_time, end_time, channel_name, channel_id, remark, create_time, update_time, create_by, update_by, is_deleted
) values (
    #{orderNo}, #{userId}, #{durationId}, #{durationValue}, #{tierId}, #{tierValue}, #{totalAmount}, #{groupIdNo}, #{liveStatus},
    #{beginTime}, #{endTime}, #{channelName}, #{channelId}, #{remark}, now(), now(), #{createBy}, #{updateBy}, #{isDeleted}
)
